import { notFound } from 'next/navigation';
import { services } from '@/lib/content';
import { buildMetadata } from '@/lib/metadata';
export function generateStaticParams(){return services.map((service)=>({slug:service.slug}));}
export function generateMetadata({params}:{params:{slug:string}}){const service=services.find((s)=>s.slug===params.slug); if(!service)return {}; return buildMetadata(service.seo, `/services/${service.slug}/`);}
export default function ServicePage({params}:{params:{slug:string}}){const service=services.find((s)=>s.slug===params.slug); if(!service)notFound(); return <><section className="page-hero"><div className="page-hero-inner"><span className="sec-lbl">Veterinary Service</span><h1 className="hero-h1">{service.title}</h1><p className="hero-body">{service.excerpt}</p></div></section><section className="content-section"><div className="content-inner detail-grid"><div>{service.acf.intro && <p>{service.acf.intro}</p>}<p>{service.excerpt}</p><a className="btn-red" href="/contact/">Request an Appointment</a></div><aside className="detail-card"><h2>Care highlights</h2><ul>{service.acf.highlights.map((item)=><li key={item}>{item}</li>)}</ul></aside></div></section><script type="application/ld+json" dangerouslySetInnerHTML={{__html:JSON.stringify({'@context':'https://schema.org','@type':'Service',name:service.title,description:service.excerpt,provider:{'@type':'VeterinaryCare',name:'Veterinary Medical Center'}})}}/></>}
